257	 *  RimeApi is for rime v1.0+
258	 */
259	typedef struct RIME_FLAVORED(rime_api_t) {
260	  int data_size;
261	
262	  /*! setup
263	   *  Call this function before accessing any other API functions.
264	   */
265	  void (*setup)(RimeTraits* traits);
266	
267	  /*! Set up the notification callbacks
268	   *  Receive notifications
269	   *  - on loading schema:
270	   *    + message_type="schema", message_value="luna_pinyin/Luna Pinyin"
271	   *  - on changing mode:
272	   *    + message_type="option", message_value="ascii_mode"
273	   *    + message_type="option", message_value="!ascii_mode"
274	   *  - on deployment:
275	   *    + session_id = 0, message_type="deploy", message_value="start"
276	   *    + session_id = 0, message_type="deploy", message_value="success"
277	   *    + session_id = 0, message_type="deploy", message_value="failure"
278	   *
