285	
286	  // entry and exit
287	
288	  void (*initialize)(RimeTraits* traits);
289	  void (*finalize)(void);
290	
291	  Bool (*start_maintenance)(Bool full_check);
292	  Bool (*is_maintenance_mode)(void);
293	  void (*join_maintenance_thread)(void);
294	
295	  // deployment
296	
297	  void (*deployer_initialize)(RimeTraits* traits);
298	  Bool (*prebuild)(void);
299	  Bool (*deploy)(void);
300	  Bool (*deploy_schema)(const char* schema_file);
301	  Bool (*deploy_config_file)(const char* file_name, const char* version_key);
302	
303	  Bool (*sync_user_data)(void);
304	
305	  // session management
306	
