314	
315	  Bool (*process_key)(RimeSessionId session_id, int keycode, int mask);
316	  // return True if there is unread commit text
317	  Bool (*commit_composition)(RimeSessionId session_id);
318	  void (*clear_composition)(RimeSessionId session_id);
319	
320	  // output
321	
322	  Bool (*get_commit)(RimeSessionId session_id, RimeCommit* commit);
323	  Bool (*free_commit)(RimeCommit* commit);
324	  Bool (*get_context)(RimeSessionId session_id,
325	                      RIME_FLAVORED(RimeContext) * context);
326	  Bool (*free_context)(RIME_FLAVORED(RimeContext) * ctx);
327	  Bool (*get_status)(RimeSessionId session_id,
328	                     RIME_FLAVORED(RimeStatus) * status);
329	  Bool (*free_status)(RIME_FLAVORED(RimeStatus) * status);
330	
331	  // runtime options
332	
333	  void (*set_option)(RimeSessionId session_id, const char* option, Bool value);
334	  Bool (*get_option)(RimeSessionId session_id, const char* option);
335	
336	  void (*set_property)(RimeSessionId session_id,
337	                       const char* prop,
338	                       const char* value);
339	  Bool (*get_property)(RimeSessionId session_id,
340	                       const char* prop,
341	                       char* value,
342	                       size_t buffer_size);
343	
344	  Bool (*get_schema_list)(RimeSchemaList* schema_list);
345	  void (*free_schema_list)(RimeSchemaList* schema_list);
346	
347	  Bool (*get_current_schema)(RimeSessionId session_id,
348	                             char* schema_id,
349	                             size_t buffer_size);
350	  Bool (*select_schema)(RimeSessionId session_id, const char* schema_id);
351	
352	  // configuration
353	
354	  Bool (*schema_open)(const char* schema_id, RimeConfig* config);
355	  Bool (*config_open)(const char* config_id, RimeConfig* config);
356	  Bool (*config_close)(RimeConfig* config);
357	  Bool (*config_get_bool)(RimeConfig* config, const char* key, Bool* value);
358	  Bool (*config_get_int)(RimeConfig* config, const char* key, int* value);
359	  Bool (*config_get_double)(RimeConfig* config, const char* key, double* value);
360	  Bool (*config_get_string)(RimeConfig* config,
361	                            const char* key,
362	                            char* value,
363	                            size_t buffer_size);
364	  const char* (*config_get_cstring)(RimeConfig* config, const char* key);
365	  Bool (*config_update_signature)(RimeConfig* config, const char* signer);
366	  Bool (*config_begin_map)(RimeConfigIterator* iterator,
367	                           RimeConfig* config,
368	                           const char* key);
369	  Bool (*config_next)(RimeConfigIterator* iterator);
370	  void (*config_end)(RimeConfigIterator* iterator);
371	
372	  // testing
373	
374	  Bool (*simulate_key_sequence)(RimeSessionId session_id,
375	                                const char* key_sequence);
376	
377	  // module
378	
379	  Bool (*register_module)(RimeModule* module);
380	  RimeModule* (*find_module)(const char* module_name);
381	
382	  Bool (*run_task)(const char* task_name);
383	
384	  //! \deprecated use get_shared_data_dir_s instead.
385	  const char* (*get_shared_data_dir)(void);
