392	  void (*get_user_data_sync_dir)(char* dir, size_t buffer_size);
393	
394	  //! initialize an empty config object
395	  /*!
396	   * should call config_close() to free the object
397	   */
398	  Bool (*config_init)(RimeConfig* config);
399	  //! deserialize config from a yaml string
400	  Bool (*config_load_string)(RimeConfig* config, const char* yaml);
401	
402	  // configuration: setters
403	  Bool (*config_set_bool)(RimeConfig* config, const char* key, Bool value);
404	  Bool (*config_set_int)(RimeConfig* config, const char* key, int value);
405	  Bool (*config_set_double)(RimeConfig* config, const char* key, double value);
406	  Bool (*config_set_string)(RimeConfig* config,
407	                            const char* key,
408	                            const char* value);
409	
410	  // configuration: manipulating complex structures
411	  Bool (*config_get_item)(RimeConfig* config,
412	                          const char* key,
413	                          RimeConfig* value);
414	  Bool (*config_set_item)(RimeConfig* config,
415	                          const char* key,
416	                          RimeConfig* value);
417	  Bool (*config_clear)(RimeConfig* config, const char* key);
418	  Bool (*config_create_list)(RimeConfig* config, const char* key);
419	  Bool (*config_create_map)(RimeConfig* config, const char* key);
420	  size_t (*config_list_size)(RimeConfig* config, const char* key);
421	  Bool (*config_begin_list)(RimeConfigIterator* iterator,
