439	  const char* (*get_version)(void);
440	
441	  //! set caret position in terms of raw input
442	  void (*set_caret_pos)(RimeSessionId session_id, size_t caret_pos);
443	
444	  //! select a candidate from current page.
445	  Bool (*select_candidate_on_current_page)(RimeSessionId session_id,
446	                                           size_t index);
447	
448	  //! access candidate list.
449	  Bool (*candidate_list_begin)(RimeSessionId session_id,
450	                               RimeCandidateListIterator* iterator);
451	  Bool (*candidate_list_next)(RimeCandidateListIterator* iterator);
452	  void (*candidate_list_end)(RimeCandidateListIterator* iterator);
453	
454	  //! access config files in user data directory, eg. user.yaml and
455	  //! installation.yaml
456	  Bool (*user_config_open)(const char* config_id, RimeConfig* config);
457	
458	  Bool (*candidate_list_from_index)(RimeSessionId session_id,
459	                                    RimeCandidateListIterator* iterator,
460	                                    int index);
461	
462	  //! prebuilt data directory.
463	  //! \deprecated use get_prebuilt_data_dir_s instead.
464	  const char* (*get_prebuilt_data_dir)(void);
465	  //! staging directory, stores data files deployed to a Rime client.
466	  //! \deprecated use get_staging_dir_s instead.
467	  const char* (*get_staging_dir)(void);
468	
469	  //! \deprecated for capnproto API, use "proto" module from librime-proto
470	  //! plugin.
471	  void (*commit_proto)(RimeSessionId session_id,
472	                       RIME_PROTO_BUILDER* commit_builder);
473	  void (*context_proto)(RimeSessionId session_id,
474	                        RIME_PROTO_BUILDER* context_builder);
475	  void (*status_proto)(RimeSessionId session_id,
476	                       RIME_PROTO_BUILDER* status_builder);
477	
478	  const char* (*get_state_label)(RimeSessionId session_id,
479	                                 const char* option_name,
480	                                 Bool state);
481	
482	  //! delete a candidate at the given index in candidate list.
483	  Bool (*delete_candidate)(RimeSessionId session_id, size_t index);
484	  //! delete a candidate from current page.
485	  Bool (*delete_candidate_on_current_page)(RimeSessionId session_id,
486	                                           size_t index);
487	
488	  RimeStringSlice (*get_state_label_abbreviated)(RimeSessionId session_id,
489	                                                 const char* option_name,
490	                                                 Bool state,
491	                                                 Bool abbreviated);
492	
493	  Bool (*set_input)(RimeSessionId session_id, const char* input);
494	
495	  void (*get_shared_data_dir_s)(char* dir, size_t buffer_size);
496	  void (*get_user_data_dir_s)(char* dir, size_t buffer_size);
497	  void (*get_prebuilt_data_dir_s)(char* dir, size_t buffer_size);
498	  void (*get_staging_dir_s)(char* dir, size_t buffer_size);
499	  void (*get_sync_dir_s)(char* dir, size_t buffer_size);
500	
501	  //! highlight a selection without committing
502	  Bool (*highlight_candidate)(RimeSessionId session_id, size_t index);
503	  //! highlight a selection without committing
504	  Bool (*highlight_candidate_on_current_page)(RimeSessionId session_id,
505	                                              size_t index);
506	
507	  Bool (*change_page)(RimeSessionId session_id, Bool backward);
508	} RIME_FLAVORED(RimeApi);
509	
510	//! API entry
511	/*!
512	 *  Acquire the version controlled RimeApi structure.
513	 */
514	RIME_API RIME_FLAVORED(RimeApi) * RIME_FLAVORED(rime_get_api)(void);
515	
516	//! Clients should test if an api function is available in the current version
517	//! before calling it.
518	#define RIME_API_AVAILABLE(api, func) \
519	  (RIME_STRUCT_HAS_MEMBER(*(api), (api)->func) && (api)->func)
520	
521	// Initializer for MSVC and GCC.
522	// 2010 Joe Lowe. Released into the public domain.
523	#if defined(__GNUC__)
524	#define RIME_MODULE_INITIALIZER(f)                  \
525	  static void f(void) __attribute__((constructor)); \
526	  static void f(void)
527	#elif defined(_MSC_VER)
528	#pragma section(".CRT$XCU", read)
529	#define RIME_MODULE_INITIALIZER(f)                                 \
530	  static void __cdecl f(void);                                     \
531	  __declspec(allocate(".CRT$XCU")) void(__cdecl * f##_)(void) = f; \
532	  static void __cdecl f(void)
533	#endif
534	
535	/*!
536	 *  Automatically register a rime module when the library is loaded.
537	 *  Clients should define functions called rime_<module_name>_initialize(),
538	 *  and rime_<module_name>_finalize().
539	 *  \sa core_module.cc for an example.
540	 */
541	#define RIME_REGISTER_MODULE(name)                       \
542	  void rime_require_module_##name() {}                   \
543	  RIME_MODULE_INITIALIZER(rime_register_module_##name) { \
544	    static RimeModule module = {0};                      \
545	    if (!module.data_size) {                             \
546	      RIME_STRUCT_INIT(RimeModule, module);              \
547	      module.module_name = #name;                        \
548	      module.initialize = rime_##name##_initialize;      \
549	      module.finalize = rime_##name##_finalize;          \
550	    }                                                    \
551	    RimeRegisterModule(&module);                         \
552	  }
553	
554	/*!
555	 *  Customize the module by assigning additional functions, eg. module->get_api.
556	 */
557	#define RIME_REGISTER_CUSTOM_MODULE(name)                       \
558	  void rime_require_module_##name() {}                          \
559	  static void rime_customize_module_##name(RimeModule* module); \
560	  RIME_MODULE_INITIALIZER(rime_register_module_##name) {        \
561	    static RimeModule module = {0};                             \
562	    if (!module.data_size) {                                    \
563	      RIME_STRUCT_INIT(RimeModule, module);                     \
564	      module.module_name = #name;                               \
565	      module.initialize = rime_##name##_initialize;             \
566	      module.finalize = rime_##name##_finalize;                 \
567	      rime_customize_module_##name(&module);                    \
568	    }                                                           \
569	    RimeRegisterModule(&module);                                \
570	  }                                                             \
571	  static void rime_customize_module_##name(RimeModule* module)
572	
573	/*!
574	 *  Defines a constant for a list of module names.
575	 */
576	#define RIME_MODULE_LIST(var, ...) const char* var[] = {__VA_ARGS__, NULL}
577	
578	/*!
579	 *  Register a phony module which, when loaded, will load a list of modules.
580	 *  \sa setup.cc for an example.
581	 */
582	#define RIME_REGISTER_MODULE_GROUP(name, ...)                       \
583	  static RIME_MODULE_LIST(rime_##name##_module_group, __VA_ARGS__); \
584	  static void rime_##name##_initialize() {                          \
585	    rime::LoadModules(rime_##name##_module_group);                  \
586	  }                                                                 \
587	  static void rime_##name##_finalize() {}                           \
588	  RIME_REGISTER_MODULE(name)
589	
590	#ifdef __cplusplus
591	}
592	#endif
593	
594	#endif  // RIME_API_H_
